	}

	expected := map[string]int{
		"startHttpServer": 1,
		"noop":            1,
		"label_agent":     1,
		"explicit_legacy": 1,
		"explicitExec":    1,
		"explicit_call":   1,
		"explicit_use":    1,
	}
	for name, count := range expected {
		if got[name] != count {
			fmt.Fprintf(os.Stderr, "missing or wrong count for %s: got %d want %d\n", name, got[name], count)
